const API_URL = 'http://localhost:3001/api/products';

export const getProducts = () => fetch(API_URL).then(r => r.json());
export const getProduct = (id) => fetch(`${API_URL}/${id}`).then(r => r.json());
export const createProduct = (data) => fetch(API_URL, { method: 'POST', headers: {'Content-Type': 'application/json'}, body: JSON.stringify(data) }).then(r => r.json());
export const updateProduct = (id, data) => fetch(`${API_URL}/${id}`, { method: 'PATCH', headers: {'Content-Type': 'application/json'}, body: JSON.stringify(data) }).then(r => r.json());
export const deleteProduct = (id) => fetch(`${API_URL}/${id}`, { method: 'DELETE' });
